UPDATE public.consent_form_templates SET fields = $JSON$[{"type": "heading", "label": "Your Ear Health", "required": false}, {"type": "textarea", "label": "What are your main concerns/symptoms with your ears?", "required": true}, {"type": "text", "label": "GP Name & Surgery", "required": false}, {"type": "radio", "label": "Have you already started to use drops or spray in your ears?", "options": ["Yes", "No"], "required": true, "followUp": "Which drops/spray, and for how long?"}, {"type": "radio", "label": "Have you had Earwax Removal Previously?", "options": ["Yes", "No"], "required": true, "followUp": "When was your last earwax removal, and where?"}, {"type": "radio", "label": "Are you aware of having an ear infection in the past 6 weeks?", "options": ["Yes", "No"], "required": true, "followUp": "When was the infection, and was it treated?"}, {"type": "radio", "label": "Have you had any coughs, colds, sinus congestion in the past 6-8 weeks that correlates to the worsening of your hearing/ears?", "options": ["Yes", "No"], "required": true, "followUp": "Please describe (when, symptoms, ongoing?)"}, {"type": "radio", "label": "Have you consulted with your GP or other professional about your ears recently?", "options": ["Yes", "No"], "required": true, "followUp": "Who did you see, when, and what was advised?"}, {"type": "radio", "label": "Have you had any surgery on your ears?", "options": ["Yes", "No"], "required": true, "followUp": "Please describe the surgery and when it was performed"}, {"type": "radio", "label": "Have you ever been told you have small or narrow ear canals?", "options": ["Yes", "No"], "required": true, "followUp": "Who told you, and any further details"}, {"type": "radio", "label": "Do you suffer with Tinnitus?", "options": ["Yes", "No"], "required": true, "followUp": "Please describe (which ear, how long, severity)"}, {"type": "radio", "label": "Are you currently experiencing any dizziness or pain in your ears?", "options": ["Yes", "No"], "required": true, "followUp": "Please describe (which ear, how long, severity)"}, {"type": "radio", "label": "Are you currently taking any anticoagulant medication? (e.g blood thinners, warfarin)", "options": ["Yes", "No"], "required": true, "followUp": "Please list the medication(s) and dose"}, {"type": "radio", "label": "Have you ever had or do you have a perforated eardrum?", "options": ["Yes", "No"], "required": true, "followUp": "Which ear, when did it happen, and is it healed?"}, {"type": "radio", "label": "Do you have or wear hearing aids?", "options": ["Yes", "No"], "required": true, "followUp": "Type of hearing aid and how often worn"}, {"type": "radio", "label": "Do you have any physical, learning, or cognitive conditions that may affect your visit or that you\u2019d like us to take into account?", "options": ["Yes", "No"], "required": true, "description": "This is to ensure we add a little extra time to appointments, to ensure nothing feels rushed. ", "followUp": "Please describe so we can support you"}, {"type": "heading", "label": "Pre-Appointment Preparation", "required": false}, {"type": "checkbox", "label": "Please confirm that you will start an Olive Oil ear spray at least 3-4 days prior (2-3 times daily) until your appointment unless you are aware of a perforated eardrum, or have discussed with Matt prior.", "required": true}, {"type": "heading", "label": "Consent \u2014 Earwax Removal", "required": false}, {"type": "info", "label": "I give my consent for earwax removal to be carried out.\n\n\u2022    I understand that every effort will be made to remove earwax during the 50-minute appointment. In some cases, due to the amount, consistency, or position of the wax, it may not be possible to remove all earwax in one session. If required, a follow-up appointment may be necessary and is chargeable at \u00a335 if booked within 4 weeks of the initial appointment.\n\n\u2022    I understand that earwax removal is not compulsory and that alternative options include self-care, no treatment, or referral to my GP or another healthcare professional.\n\n\u2022    I confirm that I have disclosed all relevant medical history, including previous ear surgery, perforated eardrum, ear infections, dizziness or vertigo, tinnitus, or any other ear-related conditions. I understand that withholding information may increase the risk of complications.\n\n\u2022    I understand that the clinician will use the most appropriate method for earwax removal based on clinical assessment, which may include microsuction, irrigation, and/or manual instrumentation.\n\n\u2022    I understand that earwax removal is not a diagnostic service. The clinician cannot diagnose medical conditions, and I may be advised to seek assessment from my GP or another healthcare professional if symptoms persist or concerns are identified.\n\n\u2022    I understand that more than one appointment may be required and that referral to another medical professional may be necessary if complications arise or if treatment cannot be safely completed.\n\n\u2022    I understand that I may ask for the procedure to be stopped at any time, for any reason.\n\n\u2022    I agree to follow the aftercare advice provided.\n\n---------------------------------------------\n\nPossible Complications of Earwax Removal I understand that possible complications may include:\n\n\u2022    Incomplete removal of earwax requiring a return visit\n\n\u2022    Temporary discomfort or pain\n\n\u2022    Minor bleeding\n\n\u2022    Temporary dizziness or vertigo\n\n\u2022    Tinnitus (ringing in the ear)\n\n\u2022    Infection\n\n\u2022    Perforation of the eardrum\n\n\u2022    Temporary or permanent changes in hearing\n\n---------------------------------------------\n\nAdditional Consent for Hearing Screening (if applicable)\n\n\u2022    I understand that hearing screening is an optional assessment and does not form part of a diagnostic audiology service.\n\n\u2022    I understand that hearing screening provides an indication only of hearing ability at the time of testing and is not a formal hearing test or medical diagnosis.\n\n\u2022    I understand that results may be affected by factors such as remaining earwax, background noise, temporary ear conditions, or equipment limitations.\n\n\u2022    I understand that the clinician cannot diagnose hearing loss or medical ear conditions and that abnormal or concerning results may require referral to my GP, an audiologist, or another healthcare professional for further assessment.\n\n---------------------------------------------\n\nPossible Risks and Limitations of Hearing Screening I understand that: \u2022    Results may not fully reflect my true hearing ability\n\n\u2022    False positive or false negative results may occur\n\n\u2022    Hearing levels can fluctuate over time\n\n\u2022    Screening does not identify all types of hearing loss or ear pathology\n\n---------------------------------------------\n\nPatient Acknowledgement and Consent By signing below, I confirm that:\n\n\u2022    I have the capacity to give informed consent and that my decision is voluntary\n\n\u2022    I have read and understood the information provided\n\n\u2022    I have had the opportunity to ask questions\n\n\u2022    I give my informed consent for earwax removal and, where applicable, hearing screening to be carried out", "required": false}, {"type": "heading", "label": "Patient Acknowledgement and Consent", "required": false}, {"type": "checkbox", "label": "I have read and understood the above consent form and would like to continue with the treatment.", "required": true}, {"type": "signature", "label": "Please write YOUR NAME below to confirm you have read and understood the above consent form and would like to continue with the treatment", "required": true}]$JSON$::jsonb, updated_at = now() WHERE id = '66b8cb6b-7b04-4b13-96ae-9bd3f35946bc';